from flask_wtf import FlaskForm
from wtforms import StringField, PasswordField
from wtforms.validators import DataRequired, Length, ValidationError
from app.models import User

class RegistrationForm(FlaskForm):
    username = StringField('Username', validators=[DataRequired(), Length(min=3)])
    email = StringField('Email', validators=[DataRequired()])
    password = PasswordField('Password', validators=[DataRequired(), Length(min=8)])

    def validate_username(self, field):
        """Check if username is already taken."""
        user = User.query.filter_by(username=field.data).first()
        if user:
            raise ValidationError('Username already taken.')

    def validate_email(self, field):
        """Check if email is already registered."""
        user = User.query.filter_by(email=field.data).first()
        if user:
            raise ValidationError('Email already registered.')

    def validate_password(self, field):
        """Enforce password complexity."""
        password = field.data
        if not any(c.isupper() for c in password):
            raise ValidationError('Password must contain an uppercase letter.')
        if not any(c.isdigit() for c in password):
            raise ValidationError('Password must contain a digit.')

from wtforms.validators import ValidationError
import re

# Function-based validator
def no_special_chars(form, field):
    if not re.match(r'^[a-zA-Z0-9_]+$', field.data):
        raise ValidationError('Only letters, numbers, and underscores allowed.')

# Class-based validator (parameterized)
class Unique:
    def __init__(self, model, field, message='Already exists.'):
        self.model = model
        self.field = field
        self.message = message

    def __call__(self, form, field):
        exists = self.model.query.filter(
            getattr(self.model, self.field) == field.data
        ).first()
        if exists:
            raise ValidationError(self.message)

# Usage in form
class UserForm(FlaskForm):
    username = StringField('Username', validators=[
        DataRequired(),
        no_special_chars,  # Function validator
        Unique(User, 'username', 'Username taken.')  # Class validator
    ])

from wtforms.validators import ValidationError
from PIL import Image
import io

class ImageDimensions:
    """Validate image dimensions."""
    def __init__(self, min_width=0, min_height=0, max_width=4000, max_height=4000):
        self.min_width = min_width
        self.min_height = min_height
        self.max_width = max_width
        self.max_height = max_height

    def __call__(self, form, field):
        if not field.data:
            return

        file = field.data
        try:
            image = Image.open(file.stream)
            width, height = image.size
            file.stream.seek(0)  # Reset stream for later save()

            if width < self.min_width or height < self.min_height:
                raise ValidationError(
                    f'Image must be at least {self.min_width}x{self.min_height}px'
                )
            if width > self.max_width or height > self.max_height:
                raise ValidationError(
                    f'Image must be at most {self.max_width}x{self.max_height}px'
                )
        except Exception as e:
            raise ValidationError(f'Invalid image: {e}')

